request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?reachable ?reachableName ?type WHERE {
  ?start a bboExt:ChoreographyTask .
  ?start bbo:name "recipe request" .
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachable .
  OPTIONAL { ?reachable bbo:name ?reachableName . }
  OPTIONAL { ?reachable a ?type . }
}
LIMIT 50
